select coalesce(sum(amount), 0) from ( select o.actual_amount as amount from crm_order o left join crm_customer c on o.customer_id = c.customer_id where o.del_flag = '0' and o.status in ('1', '2') and o.contract_id is null and date_format(o.update_time, '%Y-%m') = #{params.month}
${params.dataScope}
union all select o.actual_amount from crm_order o left join crm_customer c on o.customer_id = c.customer_id where o.del_flag = '0' and o.status in ('1', '2') and o.contract_id is not null and date_format(o.update_time, '%Y-%m') = #{params.month}
${params.dataScope}
union all select pp.actual_amount from crm_payment_plan pp left join crm_order o on pp.order_id = o.order_id left join crm_customer c on o.customer_id = c.customer_id where pp.del_flag = '0' and pp.status = '1' and date_format(pp.actual_date, '%Y-%m') = #{params.month}
${params.dataScope}
) t

